        debug!("re-attach session HEAD to main after clean");
        run("git", &["checkout", "main"], session_dir)?;
    } else {
        debug!("strip jj state from code side (no .claude in single-repo)");
        run("git", &["clean", "-xdf"], &plan.project_dir)?;
    }
